// ==========================================
// AUDIT PARSER
// يحوّل تقرير GSD الخام إلى قرارات منظمة
// ==========================================
const body = $input.item.json.body || $input.item.json;

// Accept flexible input formats
const scores = body.scores || {};
const critical = body.critical_issues || body.critical || [];
const improvements = body.improvements || [];
const pages = body.pages_tested || body.pages || [];
const rawText = body.raw_report || body.report || '';

// Build structured audit
const audit = {
  timestamp: new Date().toISOString(),
  source: body.source || 'gsd_site_audit',
  scores: {
    design: scores.design || scores.ux_ui || 0,
    security: scores.security || scores.code_security || 0,
    rtl: scores.rtl || 0,
    mobile: scores.mobile || scores.responsive || 0,
    performance: scores.performance || scores.speed || 0,
    seo: scores.seo || 0
  },
  avg_score: 0,
  critical_count: critical.length,
  critical_issues: critical,
  improvements: improvements,
  pages_tested: pages
};

// Calculate average
const vals = Object.values(audit.scores).filter(v => v > 0);
audit.avg_score = vals.length ? Math.round(vals.reduce((a,b) => a+b, 0) / vals.length * 10) / 10 : 0;

// === GENERATE DECISIONS ===
const decisions = [];

// Map critical issues to decisions
critical.forEach((issue, i) => {
  const issueLower = (issue.title || issue.name || issue || '').toLowerCase();
  let agent = 'borhan';
  let confidence = 0.90;

  // Route to correct agent
  if (issueLower.match(/xss|injection|security|auth|webhook|rate limit|header/)) {
    agent = 'borhan';
    confidence = 0.95;
  } else if (issueLower.match(/404|broken|link|redirect|subscribe/)) {
    agent = 'borhan';
    confidence = 0.98;
  } else if (issueLower.match(/design|color|font|spacing|ui|ux|visual/)) {
    agent = 'sham';
    confidence = 0.82;
  } else if (issueLower.match(/seo|meta|structured|sitemap|robots/)) {
    agent = 'content_engine';
    confidence = 0.75;
  } else if (issueLower.match(/image|performance|speed|lazy|webp/)) {
    agent = 'content_engine';
    confidence = 0.80;
  }

  decisions.push({
    id: `audit_${i}`,
    action: issue.fix || issue.action || `إصلاح: ${issue.title || issue.name || issue}`,
    target_agent: agent,
    priority: issue.severity === 'critical' || i < 3 ? 'critical' : 'high',
    confidence,
    reason: issue.impact || issue.reason || `من تقرير GSD — ${issue.title || issue}`,
    file: issue.file || '',
    category: issue.category || 'site_audit'
  });
});

// Add improvement decisions
improvements.slice(0, 5).forEach((imp, i) => {
  decisions.push({
    id: `imp_${i}`,
    action: imp.action || imp.title || imp,
    target_agent: 'sham',
    priority: 'medium',
    confidence: 0.70,
    reason: imp.reason || 'تحسين من تقرير GSD',
    category: 'improvement'
  });
});

return {
  json: {
    audit,
    decisions,
    decisions_count: decisions.length,
    status: audit.critical_count >= 3 ? 'critical' : audit.critical_count >= 1 ? 'warning' : 'stable'
  }
};
